mapper.select:
SELECT id, game_type as gameType, set_name as setName, card_name as cardName, card_number as cardNumber, rarity, language, manufacturer, image_url as imageUrl, description, is_active as isActive, pokemon_id as pokemonId, hp, evolution_stage as evolutionStage, pokemon_card_type as pokemonCardType, sub_type as subType FROM card_master
is_active = true
AND game_type = #{gameType}
AND card_name LIKE CONCAT('%', #{cardName}, '%')
AND set_name LIKE CONCAT('%', #{setName}, '%')
AND card_number = #{cardNumber}
AND rarity = #{rarity}
AND pokemon_card_type = #{pokemonCardType}
AND sub_type = #{subType}
AND type = #{type}
AND evolution_stage = #{evolutionStage}
